(function () {
  "use strict";

  var $period = document.getElementById("analytics-period");
  var $tabs = document.querySelectorAll(".org-tab[data-unit]");
  var $kpiTotal = document.querySelector("[data-kpi-total]");
  var $kpiSigned = document.querySelector("[data-kpi-signed]");
  var $kpiPending = document.querySelector("[data-kpi-pending]");
  var $kpiPct = document.querySelector("[data-kpi-pct]");
  var $kpiBar = document.querySelector("[data-kpi-bar]");
  var $byTemplate = document.querySelector("[data-bar-by-template]");
  var $byUnit = document.querySelector("[data-bar-by-unit]");

  var activeUnit = "region";

  async function api(method, url) {
    var r = await fetch(url, {
      method: method,
      headers: { "Accept": "application/json", "X-Requested-With": "XMLHttpRequest" },
    });
    if (!r.ok) {
      var msg = "שגיאה " + r.status;
      try { var d = await r.json(); if (d.detail) msg = d.detail; } catch (_e) {}
      throw new Error(msg);
    }
    return r.json();
  }

  function el(tag, opts, children) {
    var n = document.createElement(tag);
    if (opts) {
      if (opts.className) n.className = opts.className;
      if (opts.text != null) n.textContent = opts.text;
      if (opts.attrs) Object.keys(opts.attrs).forEach(function (k) { n.setAttribute(k, opts.attrs[k]); });
    }
    if (children) children.forEach(function (c) { n.appendChild(c); });
    return n;
  }

  function pctColor(pct) {
    if (pct >= 80) return "#16a34a";  // green-600
    if (pct >= 50) return "#ca8a04";  // yellow-600
    return "#dc2626";                  // red-600
  }

  function renderBars(container, rows, nameKey) {
    if (!rows || !rows.length) {
      container.replaceChildren(el("div", {
        className: "org-text-sm org-text-muted",
        text: "אין נתונים לתקופה זו.",
        attrs: { style: "padding: var(--org-space-3);" },
      }));
      return;
    }
    var frag = document.createDocumentFragment();
    rows.forEach(function (r) {
      var row = el("div", { className: "org-bar-row" });

      var labelLine = el("div", { className: "org-bar-row__head" });
      labelLine.appendChild(el("span", { className: "org-bar-row__label", text: r[nameKey] || "—" }));
      labelLine.appendChild(el("span", {
        className: "org-bar-row__stat",
        text: r.signed + " / " + r.total + " (" + r.signed_percentage + "%)",
      }));
      row.appendChild(labelLine);

      var track = el("div", { className: "org-bar-row__track" });
      var fill = el("div", { className: "org-bar-row__fill" });
      fill.style.width = Math.max(2, r.signed_percentage) + "%";
      fill.style.background = pctColor(r.signed_percentage);
      track.appendChild(fill);
      row.appendChild(track);

      frag.appendChild(row);
    });
    container.replaceChildren(frag);
  }

  async function loadOverview(days) {
    try {
      var d = await api("GET", "/org/api/analytics/overview?days=" + days);
      $kpiTotal.textContent = String(d.total_sent);
      $kpiSigned.textContent = String(d.total_signed);
      $kpiPending.textContent = String(d.total_pending);
      $kpiPct.textContent = d.signed_percentage + "%";
      $kpiBar.style.width = d.signed_percentage + "%";
    } catch (e) {
      $kpiTotal.textContent = "—";
      $kpiSigned.textContent = "—";
      $kpiPending.textContent = "—";
      $kpiPct.textContent = "—";
      $kpiBar.style.width = "0%";
    }
  }

  async function loadTemplates(days) {
    try {
      var d = await api("GET", "/org/api/analytics/by-template?days=" + days);
      renderBars($byTemplate, d.rows, "template_name");
    } catch (e) {
      $byTemplate.replaceChildren(el("div", {
        className: "org-text-sm org-text-muted", text: e.message,
        attrs: { style: "padding: var(--org-space-3);" },
      }));
    }
  }

  async function loadUnit(days, unit) {
    try {
      var d = await api("GET", "/org/api/analytics/by-" + unit + "?days=" + days);
      renderBars($byUnit, d.rows, "unit_name");
    } catch (e) {
      $byUnit.replaceChildren(el("div", {
        className: "org-text-sm org-text-muted", text: e.message,
        attrs: { style: "padding: var(--org-space-3);" },
      }));
    }
  }

  function refresh() {
    var days = parseInt($period.value, 10) || 30;
    loadOverview(days);
    loadTemplates(days);
    loadUnit(days, activeUnit);
  }

  $period.addEventListener("change", refresh);

  $tabs.forEach(function (t) {
    t.addEventListener("click", function () {
      $tabs.forEach(function (x) { x.classList.remove("is-active"); });
      t.classList.add("is-active");
      activeUnit = t.getAttribute("data-unit") || "region";
      var days = parseInt($period.value, 10) || 30;
      loadUnit(days, activeUnit);
    });
  });

  refresh();
})();